{
  "minimumDependencyAge": "P7D"
}

{
  "name": "@db/redis",
  "version": "0.41.2",
  "exports": {
    ".": "./mod.ts",
    "./experimental/pool": "./experimental/pool/mod.ts",
    "./experimental/cluster": "./experimental/cluster/mod.ts",
    "./experimental/web-streams-connection": "./experimental/web_streams_connection/mod.ts"
  },
  "exclude": [
    "benchmark/node_modules",
    "tmp"
  ],
  "lint": {
    "exclude": [
      "benchmark/benchmark.js",
      "benchmark/ioredis.js"
    ],
    "plugins": ["jsr:@uki00a/deno-lint-plugin-extra-rules@0.9.0"],
    "rules": { "include": ["no-console"] }
  },
  "test": {
    "exclude": ["benchmark/", "vendor/"],
    "permissions": {
      "net": ["127.0.0.1"],
      "read": ["tests"],
      "write": ["tests/tmp"],
      "run": ["redis-server", "redis-cli"],
      "env": ["REDIS_VERSION"]
    },
    "sanitizeOps": true,
    "sanitizeResources": true
  },
  "permissions": {
    "bench:deno-redis": {
      "net": ["127.0.0.1:6379"],
      "env": [
        "NODE_DISABLE_COLORS",
        "TERM",
        "TERM_PROGRAM",
        "GRACEFUL_FS_PLATFORM",
        "TEST_GRACEFUL_FS_GLOBAL_PATCH"
      ],
      "write": ["tmp"]
    }
  },
  "publish": {
    "exclude": [
      ".denov",
      ".editorconfig",
      ".octocov.yml",
      ".github",
      "import_map.dev.json",
      "import_map.test.json",
      "benchmark/",
      "tests/",
      "**/*_test.ts",
      "tools/"
    ]
  },
  "minimumDependencyAge": 1440,
  "tasks": {
    "lock": "deno cache --reload --import-map=import_map.dev.json mod.ts experimental/**/mod.ts tests/**/*.ts benchmark/*.ts",
    "check": {
      "dependencies": ["check:lint", "check:deno.json", "typecheck"]
    },
    "check:lint": "deno lint && deno fmt --check",
    "check:deno.json": "deno run -R=deno.json --import-map=import_map.dev.json @uki00a/deno-json-lint",
    "typecheck": "cat deno.json | jq '.exports.[]' | xargs deno check",
    "test": "DENO_FUTURE=1 deno test --permission-set --coverage=coverage --trace-leaks --frozen-lockfile",
    "test:doc": "deno check --doc-only --import-map=import_map.test.json README.md experimental/cluster/README.md",
    "bench:deno-redis": "DENO_NO_PACKAGE_JSON=1 deno run --unstable --permission-set=bench:deno-redis --import-map=import_map.dev.json benchmark/deno-redis.ts",
    "bench:ioredis": "node benchmark/ioredis.js"
  },
  "deno-json-lint": {
    "rules": {
      "no-restricted-fields": ["error", {
        "fields": {
          "imports": "Use `import_map.dev.json` instead."
        }
      }]
    }
  }
}

{
  "name": "@oak/oak",
  "version": "17.2.0",
  "exports": {
    ".": "./mod.ts",
    "./application": "./application.ts",
    "./body": "./body.ts",
    "./context": "./context.ts",
    "./etag": "./middleware/etag.ts",
    "./http_server_bun": "./http_server_bun.ts",
    "./http_server_native": "./http_server_native.ts",
    "./http_server_node": "./http_server_node.ts",
    "./middleware": "./middleware.ts",
    "./proxy": "./middleware/proxy.ts",
    "./request": "./request.ts",
    "./response": "./response.ts",
    "./router": "./router.ts",
    "./send": "./send.ts",
    "./serve": "./middleware/serve.ts",
    "./testing": "./testing.ts"
  },
  "publish": {
    "exclude": [
      ".devcontainer",
      ".github",
      ".vscode",
      "examples",
      "fixtures",
      "docs",
      "**/*.test.ts",
      "test_deps.ts"
    ]
  },
  "tasks": {
    "coverage": "deno coverage --lcov ./cov",
    "example": "deno run --allow-net examples/echoServer.ts",
    "test": "deno test --allow-read --allow-write --allow-net --parallel --ignore=npm",
    "test:coverage": "deno test --coverage=./cov --junit-path=junit.xml --allow-read --allow-write --allow-net --cert ./examples/tls/RootCA.crt --parallel --ignore=npm"
  },
  "fmt": {
    "exclude": ["README.md", ".github/copilot-instructions.md"]
  },
  "lint": {
    "rules": {
      "exclude": ["no-import-prefix"]
    }
  },
  "lock": false
}

{
  "name": "@hexagon/croner",
  "version": "10.0.1",
  "exports": "./src/croner.ts",
  "lint": {
    "include": ["src", "build"]
  },
  "fmt": {
    "include": ["src", "test", "build"],
    "lineWidth": 100
  },
  "tasks": {
    "pre-commit": "deno fmt --check && deno lint && deno check src/croner.ts",
    "test": "deno task build:prep && deno test --allow-read",
    "build:prep": "deno install",
    "build:clean": "deno run --allow-read --allow-write --allow-env --allow-sys build/build.ts -- clean",
    "build:npm": "deno run --allow-read --allow-write --allow-env --allow-sys build/build.ts -- package",
    "build:esbuild": "deno run --allow-read --allow-write --allow-env --allow-run --allow-sys build/build.ts -- build",
    "build": "deno task build:clean && deno task build:prep && deno test --allow-read && deno task build:esbuild  && deno task build:npm",
    "check-deps": "deno run -A jsr:@check/deps"
  },
  "nodeModulesDir": "auto",
  "imports": {
    "@cross/fs": "jsr:@cross/fs@~0.1.11",
    "@cross/test": "jsr:@cross/test@~0.0.14",
    "@std/assert": "jsr:@std/assert@~1.0.6",
    "@std/path": "jsr:@std/path@~1.1.2",
    "esbuild": "npm:esbuild@0.27.0",
    "esbuild-plugin-d.ts": "npm:esbuild-plugin-d.ts@~1.3.1"
  },
  "publish": {
    "exclude": ["build", "docs", "test", ".github", ".gitattributes", "croner.png", "SECURITY.md"]
  }
}
